const QUESTIONS_CISM_C1 = [
  { id:10041, domain:1, level:1, question:"Which of the following BEST describes information security governance?", options:["A Set of technical controls protecting data confidentiality","B Collection of security policies and procedures","C Process of identifying and mitigating security threats","D System by which an organization directs and controls information security"], correct:3, explanation:"Information security governance is the system by which an organization directs and controls information security, ensuring accountability and alignment with business objectives." },
  { id:10042, domain:1, level:1, question:"What is the PRIMARY responsibility of the board of directors regarding information security?", options:["A Conducting security audits","B Providing oversight and ensuring adequate resources for security","C Implementing technical security controls","D Writing security policies"], correct:1, explanation:"The board of directors is primarily responsible for providing oversight and ensuring that adequate resources are allocated to information security to protect organizational assets." },
  { id:10043, domain:1, level:2, question:"Which framework is MOST commonly used as a basis for IT governance including information security governance?", options:["A ITIL","B NIST CSF","C ISO 27001","D COBIT"], correct:3, explanation:"COBIT (Control Objectives for Information and Related Technologies) is most commonly used as a comprehensive IT governance framework that includes information security governance components." },
  { id:10044, domain:1, level:1, question:"The CISO role is BEST described as:", options:["A A technical role focused on firewall and network security management","B An executive role responsible for aligning security strategy with business objectives","C A compliance role focused solely on regulatory requirements","D An operational role managing the security operations center"], correct:1, explanation:"The CISO is an executive role responsible for developing and maintaining the security strategy and ensuring alignment with business objectives across the organization." },
  { id:10045, domain:1, level:2, question:"Which document establishes the authority and scope of an information security program?", options:["A Security program charter","B Security standard","C Security procedure","D Security guideline"], correct:0, explanation:"A security program charter formally establishes the authority, scope, roles, and responsibilities of the information security program, providing its organizational mandate." },
  { id:10046, domain:1, level:3, question:"An organization's security strategy MUST be aligned with the business strategy primarily because:", options:["A It ensures security investments support organizational goals and risk tolerance","B Security controls are more effective when business-aligned","C It simplifies compliance with regulations","D It reduces the cost of security controls"], correct:0, explanation:"Security strategy must align with business strategy to ensure that security investments support organizational goals, reflect the appropriate risk tolerance, and enable rather than hinder business operations." },
  { id:10047, domain:1, level:1, question:"In the security policy hierarchy, which document provides the MOST specific guidance on performing a task?", options:["A Procedure","B Standard","C Guideline","D Policy"], correct:0, explanation:"Procedures provide the most specific, step-by-step guidance on how to perform a particular task, sitting at the most granular level of the security policy hierarchy." },
  { id:10048, domain:1, level:2, question:"Which of the following BEST represents a security metric useful for governance reporting?", options:["A Number of firewall rules configured","B Percentage of employees completing security awareness training","C Number of servers patched last week","D Size of the security operations team"], correct:1, explanation:"The percentage of employees completing security awareness training is a meaningful governance metric because it measures program effectiveness and organizational risk reduction in a way meaningful to leadership." },
  { id:10049, domain:1, level:2, question:"A security steering committee is PRIMARILY responsible for:", options:["A Performing penetration tests","B Managing daily security operations","C Providing strategic direction and oversight for the security program","D Implementing security technologies"], correct:2, explanation:"A security steering committee provides strategic direction, prioritizes security initiatives, and ensures executive oversight of the security program across business units." },
  { id:10050, domain:1, level:1, question:"Which of the following is the BEST definition of segregation of duties?", options:["A Assigning all security tasks to dedicated security staff","B Requiring dual approval for all financial transactions","C Dividing critical tasks among multiple individuals to prevent fraud or error","D Separating development and production environments"], correct:2, explanation:"Segregation of duties divides critical tasks among multiple individuals so that no single person can complete a sensitive process alone, reducing the risk of fraud or error." },
  { id:10051, domain:1, level:3, question:"When developing a security governance framework, the FIRST step should be to:", options:["A Select security technologies","B Define security metrics","C Establish security policies","D Understand the organizational context and business objectives"], correct:3, explanation:"The foundation of any security governance framework must be a clear understanding of the organizational context and business objectives so that the framework supports rather than conflicts with the organization's mission." },
  { id:10052, domain:1, level:2, question:"ISO 27001 is BEST described as:", options:["A A prescriptive technical standard for network security","B A government regulation for data protection","C An international standard for establishing an information security management system","D A framework for IT service management"], correct:2, explanation:"ISO 27001 is an international standard that specifies requirements for establishing, implementing, maintaining, and continually improving an Information Security Management System (ISMS)." },
  { id:10053, domain:1, level:1, question:"The data owner is PRIMARILY responsible for:", options:["A Day-to-day management of data storage systems","B Classifying data and determining access requirements","C Implementing encryption on data at rest","D Backing up data on a regular schedule"], correct:1, explanation:"The data owner, typically a business manager, is responsible for classifying data and defining access requirements and acceptable use policies for that data." },
  { id:10054, domain:1, level:2, question:"Which of the following BEST describes the relationship between security policies and security standards?", options:["A Policies define what must be done; standards define how to meet policy requirements","B Policies and standards serve the same purpose","C Standards replace policies once implemented","D Standards are more general than policies"], correct:0, explanation:"Policies state the high-level requirements and intent (what must be done), while standards provide specific, mandatory requirements for how to comply with the policy." },
  { id:10055, domain:1, level:3, question:"A newly appointed CISO discovers that security initiatives are not aligned with business priorities. The BEST first action is to:", options:["A Implement new security technologies immediately","B Conduct a comprehensive security audit","C Revise all existing security policies","D Meet with business leaders to understand organizational goals and risk appetite"], correct:3, explanation:"Understanding business goals and risk appetite is the essential foundation for aligning security with the organization; without this understanding, any changes risk compounding the misalignment." },
  { id:10056, domain:1, level:1, question:"The NIST Cybersecurity Framework (CSF) is organized around which core functions?", options:["A Plan, Do, Check, Act","B Govern, Manage, Operate, Measure","C Prevent, Detect, Correct","D Identify, Protect, Detect, Respond, Recover"], correct:3, explanation:"The NIST CSF core functions are Identify, Protect, Detect, Respond, and Recover, providing a comprehensive approach to managing cybersecurity risk." },
  { id:10057, domain:1, level:2, question:"Security governance maturity models are used PRIMARILY to:", options:["A Identify specific security vulnerabilities","B Assess the current state of security governance and guide improvement","C Certify that security controls are in place","D Benchmark security spending against industry peers"], correct:1, explanation:"Security governance maturity models help organizations assess their current capabilities, identify gaps, and provide a roadmap for improving governance practices over time." },
  { id:10058, domain:1, level:2, question:"Which of the following BEST describes the role of a data custodian?", options:["A Implementing and managing the technical controls protecting data","B Classifying data and setting access policies","C Approving access requests for sensitive data","D Determining the business value of data assets"], correct:0, explanation:"The data custodian (often IT staff) is responsible for the technical implementation and management of the controls protecting data as directed by the data owner." },
  { id:10059, domain:1, level:3, question:"An organization wants to demonstrate security governance effectiveness to its board. The MOST appropriate approach is to:", options:["A Present a list of all security tools deployed","B Show the number of security incidents blocked","C Share detailed technical vulnerability reports","D Provide metrics aligned to business risk and strategic objectives"], correct:3, explanation:"Board-level reporting should translate security activities into business risk terms and demonstrate how security investments contribute to strategic objectives, not technical details." },
  { id:10060, domain:1, level:1, question:"Which of the following is an example of a security guideline?", options:["A All passwords must be at least 12 characters","B Recommended practices for creating strong passwords","C Users must lock workstations when unattended","D All remote access must use multi-factor authentication"], correct:1, explanation:"Guidelines are recommended, non-mandatory practices; suggesting best practices for strong passwords is advisory rather than a mandated requirement, making it a guideline." },
  { id:10061, domain:1, level:2, question:"The PRIMARY purpose of aligning the security program with business objectives is to:", options:["A Ensure security enables and supports the business rather than hindering it","B Reduce security costs","C Simplify the security architecture","D Improve technical security capabilities"], correct:0, explanation:"Aligning security with business objectives ensures security investments are focused on protecting what matters most to the business and enabling rather than obstructing business operations." },
  { id:10062, domain:1, level:1, question:"Which governance body typically has final accountability for information security in an organization?", options:["A The CISO","B The board of directors","C The IT department","D The security steering committee"], correct:1, explanation:"The board of directors holds ultimate accountability for the organization's risk management, including information security, as part of their fiduciary responsibilities." },
  { id:10063, domain:1, level:3, question:"When establishing a security governance framework, which of the following is the MOST critical success factor?", options:["A Executive support and commitment to security","B Having the latest security technologies","C A large security budget","D A comprehensive security policy library"], correct:0, explanation:"Executive support and commitment are the most critical success factors because without leadership buy-in, security governance initiatives lack the authority and resources needed for effective implementation." },
  { id:10064, domain:1, level:2, question:"In a COBIT-based governance model, which domain addresses 'Evaluate, Direct, and Monitor'?", options:["A BAI (Build, Acquire, Implement)","B APO (Align, Plan, Organize)","C DSS (Deliver, Service, Support)","D EDM (Evaluate, Direct, Monitor)"], correct:3, explanation:"COBIT 2019 includes the EDM (Evaluate, Direct, Monitor) governance domain, which represents the board-level governance activities distinct from management domains." },
  { id:10065, domain:1, level:1, question:"Which of the following BEST describes a security policy?", options:["A A high-level statement of management intent regarding security","B Recommended best practices for security operations","C Specific technical settings required for security compliance","D Step-by-step instructions for completing a security task"], correct:0, explanation:"A security policy is a high-level statement of management's intent, goals, and principles regarding information security, from which standards and procedures are derived." },
  { id:10066, domain:1, level:2, question:"The Information System Security Officer (ISSO) role is PRIMARILY responsible for:", options:["A Developing enterprise-wide security strategy","B Chairing the security steering committee","C Managing security for a specific system or application","D Approving enterprise security policies"], correct:2, explanation:"The ISSO is responsible for ensuring that security requirements are defined and implemented for a specific information system, serving as the security point of contact for that system." },
  { id:10067, domain:1, level:3, question:"An organization is expanding into a new market with different regulatory requirements. The security governance framework should be updated to:", options:["A Replace all existing policies with new region-specific ones","B Create a completely separate security program for the new market","C Add regulatory requirements to the existing framework while maintaining core principles","D Wait until a security incident occurs before updating the framework"], correct:2, explanation:"Security governance frameworks should be updated to incorporate new regulatory requirements while maintaining the core principles, avoiding unnecessary duplication or fragmentation of the security program." },
  { id:10068, domain:1, level:1, question:"Which of the following BEST represents a key performance indicator (KPI) for information security governance?", options:["A Number of servers in the DMZ","B Number of security tools licensed","C Percentage of critical assets with up-to-date risk assessments","D Amount of data stored in the cloud"], correct:2, explanation:"A KPI should measure progress toward security goals; the percentage of critical assets with current risk assessments directly measures the effectiveness of a key governance process." },
  { id:10069, domain:1, level:2, question:"Security culture is BEST defined as:", options:["A The collection of security policies an organization has published","B The security training curriculum used for new employees","C Shared values, beliefs, and behaviors regarding security across the organization","D The technical security controls deployed in an organization"], correct:2, explanation:"Security culture encompasses the shared values, beliefs, attitudes, and behaviors that shape how people think about and act on security in their daily work." },
  { id:10070, domain:1, level:2, question:"Which of the following BEST describes the concept of 'risk appetite' in security governance?", options:["A The amount of risk an organization is willing to accept in pursuit of its objectives","B The maximum financial loss an organization can sustain","C The number of security incidents tolerated per year","D The percentage of budget allocated to security"], correct:0, explanation:"Risk appetite is the amount and type of risk an organization is willing to accept in pursuit of its objectives, forming a key governance parameter for security decision-making." },
  { id:10071, domain:1, level:3, question:"A security program's effectiveness is BEST measured by:", options:["A The reduction in residual risk aligned with business objectives","B The number of compliance certifications achieved","C The size and budget of the security team","D The number of security controls implemented"], correct:0, explanation:"Effective security programs should demonstrate measurable reduction in residual risk in ways that align with business objectives, not simply count activities or resources." },
  { id:10072, domain:1, level:1, question:"Which of the following is NOT a core element of an information security governance framework?", options:["A Penetration testing tools","B Strategy","C Processes","D People"], correct:0, explanation:"Core governance framework elements include strategy, people, processes, and technology at an organizational level; specific tools like penetration testing tools are operational components, not governance framework elements." },
  { id:10073, domain:1, level:2, question:"When is it MOST appropriate to escalate a security matter to the board of directors?", options:["A When security risks could materially impact the organization's objectives","B When a routine security audit is completed","C When the security team disagrees on a technical solution","D When a minor technical vulnerability is discovered"], correct:0, explanation:"Board escalation is appropriate when security risks could materially impact the organization's strategic objectives, financial performance, reputation, or regulatory standing." },
  { id:10074, domain:1, level:1, question:"Which term describes the formal document that defines the security roles, responsibilities, and authority within an organization?", options:["A Security charter","B Security procedure","C Security policy","D Security standard"], correct:0, explanation:"A security charter formally defines the mandate, scope, roles, responsibilities, and authority of the security function within the organization." },
  { id:10075, domain:1, level:3, question:"An organization's security governance program is described as 'ad hoc.' This MOST likely means:", options:["A The organization has achieved ISO 27001 certification","B Security processes are well-documented and consistently applied","C Security is managed reactively without formal processes or consistent practices","D Security is fully integrated into all business processes"], correct:2, explanation:"An 'ad hoc' security governance maturity level means security is managed reactively, without formal processes, documentation, or consistent practices across the organization." },
  { id:10076, domain:1, level:2, question:"Which of the following governance documents would be MOST appropriate for communicating executive management's commitment to security to all employees?", options:["A An information security policy signed by senior management","B A detailed security procedure manual","C A technical security standard","D A security architecture document"], correct:0, explanation:"An information security policy signed by senior management visibly demonstrates executive commitment and communicates the organization's security expectations to all employees." },
  { id:10077, domain:1, level:2, question:"The PRIMARY goal of security awareness programs from a governance perspective is to:", options:["A Create a security-conscious culture that reduces human-factor risks","B Train technical staff on security tools","C Satisfy compliance requirements","D Teach employees about specific cyber threats"], correct:0, explanation:"From a governance perspective, security awareness programs aim to build a security-conscious culture where employees understand their responsibilities and behave in ways that reduce risk." },
  { id:10078, domain:1, level:1, question:"Which of the following BEST describes 'governance' as opposed to 'management' in the context of security?", options:["A Governance sets direction and accountability; management implements and operates","B Governance and management are the same thing","C Governance focuses on daily operations; management sets strategic direction","D Governance is performed by IT staff; management is performed by executives"], correct:0, explanation:"Governance sets strategic direction, policies, and accountability structures, while management implements those directives and operates day-to-day security processes." },
  { id:10079, domain:1, level:3, question:"A CISO is asked to justify the security budget to the board. The MOST effective approach is to:", options:["A List all security tools and their costs","B Compare spending to industry benchmarks","C Present security spending in terms of risk reduction and business value protected","D Show the number of incidents prevented"], correct:2, explanation:"Justifying security investments to the board requires framing spending in terms of risk reduction and business value protected, translating technical activities into financial and strategic terms board members understand." },
  { id:10080, domain:1, level:2, question:"Which of the following BEST represents the scope of information security governance?", options:["A Only the IT department's activities","B External-facing systems and networks","C Technical security controls only","D All organizational activities that could affect information security risk"], correct:3, explanation:"Information security governance encompasses all organizational activities that affect security risk, including people, processes, and technology across all business units, not just IT." },
  { id:10081, domain:1, level:1, question:"A security standard is BEST described as:", options:["A Mandatory, specific requirements that support a security policy","B A high-level statement of intent about security","C Optional guidance for improving security","D A step-by-step process for completing security tasks"], correct:0, explanation:"Standards are mandatory, specific requirements that define how policies are to be implemented, providing concrete and measurable criteria for compliance." },
  { id:10082, domain:1, level:2, question:"Which of the following is the MOST important characteristic of effective security metrics?", options:["A They should be technically detailed","B They should measure the maximum number of security events","C They should be aligned to business objectives and decision-making needs","D They should be collected as frequently as possible"], correct:2, explanation:"Effective security metrics must be aligned to business objectives and support decision-making, enabling leadership to understand and manage security risk in the context of organizational goals." },
  { id:10083, domain:1, level:3, question:"An organization is acquiring another company. From a security governance perspective, the FIRST priority should be to:", options:["A Immediately integrate all IT systems","B Assess the security posture and governance of the acquired entity","C Apply all existing policies to the acquired company immediately","D Wait until the acquisition is complete before addressing security"], correct:1, explanation:"Assessing the security posture and governance of the acquired entity early helps identify risks and integration challenges before they become inherited vulnerabilities." },
  { id:10084, domain:1, level:1, question:"Which of the following is the BEST example of a security governance activity?", options:["A Establishing security roles and responsibilities across the organization","B Patching a critical vulnerability","C Deploying a new intrusion detection system","D Responding to a security incident"], correct:0, explanation:"Establishing security roles and responsibilities is a governance activity because it creates the accountability structure and organizational framework that enables security management." },
  { id:10085, domain:1, level:2, question:"Which concept in security governance describes the principle that individuals should be given only the access needed to perform their job functions?", options:["A Need to know","B Least privilege","C Segregation of duties","D Role-based access"], correct:1, explanation:"Least privilege is the principle that individuals and systems should be granted only the minimum access required to perform their authorized functions, reducing the attack surface." },
  { id:10086, domain:1, level:2, question:"The NIST CSF 'Govern' function (added in CSF 2.0) is primarily concerned with:", options:["A Detecting cybersecurity events","B Recovering from cybersecurity incidents","C Implementing protective technologies","D Establishing organizational context, risk management strategy, and accountability"], correct:3, explanation:"The NIST CSF 2.0 Govern function addresses organizational context, risk management strategy, roles and responsibilities, policies, and oversight — the foundational governance elements." },
  { id:10087, domain:1, level:3, question:"When a conflict exists between security requirements and business operations, the BEST approach is to:", options:["A Always enforce security requirements regardless of business impact","B Ignore security requirements if business operations are affected","C Work with business leaders to find risk-based solutions that balance security and operations","D Escalate all conflicts to legal and compliance"], correct:2, explanation:"Security governance requires balancing security requirements with business needs; working collaboratively with business leaders to find risk-based solutions maintains both security effectiveness and business enablement." },
  { id:10088, domain:1, level:1, question:"Which of the following BEST describes a security governance model?", options:["A The technical architecture for security systems","B The structure that defines decision rights, accountability, and oversight for security","C The collection of all security technologies deployed","D The process for responding to security incidents"], correct:1, explanation:"A security governance model defines the structure of decision rights, accountability mechanisms, and oversight processes that govern how security is managed across the organization." },
  { id:10089, domain:1, level:2, question:"Regulatory compliance governance is BEST described as:", options:["A Implementing controls to meet the minimum requirements of applicable regulations","B Ensuring the organization identifies, tracks, and manages compliance with applicable laws and regulations","C Hiring compliance staff to manage regulatory relationships","D Achieving compliance certifications for marketing purposes"], correct:1, explanation:"Regulatory compliance governance encompasses the processes for identifying applicable regulations, tracking requirements, implementing controls, and managing ongoing compliance across the organization." },
  { id:10090, domain:1, level:2, question:"Which of the following is the PRIMARY benefit of integrating security governance with corporate governance?", options:["A Security receives appropriate attention at the highest organizational levels","B Technical security decisions are made by the board","C It eliminates the need for separate security policies","D It reduces the need for a dedicated CISO"], correct:0, explanation:"Integrating security governance with corporate governance ensures that security receives appropriate executive attention, resources, and oversight as a strategic organizational concern." },
  { id:10091, domain:1, level:3, question:"A key indicator that security governance is immature is:", options:["A Security decisions are made reactively and in isolation from the business","B Security is viewed as a business enabler","C Security decisions are made with input from business stakeholders","D The organization has a defined risk appetite"], correct:0, explanation:"Reactive, isolated security decision-making indicates immature governance where security lacks integration with business strategy and operates without the structures needed for consistent, proactive management." },
  { id:10092, domain:1, level:1, question:"Which of the following BEST describes the concept of 'accountability' in security governance?", options:["A Documenting all security incidents and responses","B Ensuring that all security controls are technically effective","C Requiring all employees to attend security training","D Assigning clear ownership for security outcomes and ensuring individuals can be held answerable"], correct:3, explanation:"Accountability in security governance means assigning clear ownership for security responsibilities and creating mechanisms by which individuals and organizational units can be held answerable for outcomes." },
  { id:10093, domain:1, level:2, question:"Which of the following BEST describes the relationship between an organization's risk appetite and its security controls?", options:["A Security controls should be implemented to reduce risk to a level within the organization's risk appetite","B Organizations with high risk appetite need more security controls","C Risk appetite has no direct relationship to security control selection","D Organizations should always minimize risk regardless of their risk appetite"], correct:0, explanation:"Security controls should be calibrated to reduce residual risk to within the organization's defined risk appetite, avoiding both over-investment and under-investment in controls." },
  { id:10094, domain:1, level:3, question:"An organization's board is asking the CISO for a single metric to assess the overall health of the security program. The MOST appropriate metric would be:", options:["A Number of security incidents in the last quarter","B Security budget as a percentage of IT spend","C Number of vulnerabilities patched","D Composite risk score reflecting alignment with business objectives"], correct:3, explanation:"A composite risk score aligned to business objectives provides the board with a meaningful, strategic view of security health rather than operational metrics that don't reflect overall program effectiveness." },
  { id:10095, domain:1, level:1, question:"Which governance document is MOST appropriate for communicating mandatory configuration requirements for security systems?", options:["A Security policy","B Security guideline","C Security standard","D Security charter"], correct:2, explanation:"Security standards contain mandatory, specific technical requirements such as configuration baselines, making them the appropriate document for specifying required system settings." },
  { id:10096, domain:1, level:2, question:"The MOST important reason for conducting periodic reviews of security policies is to:", options:["A Ensure policies remain relevant as threats, technology, and business needs evolve","B Satisfy audit requirements","C Give the security team something to do","D Demonstrate compliance with regulations"], correct:0, explanation:"Regular policy reviews ensure that security policies remain current and effective as the threat landscape, business operations, technologies, and regulatory requirements change over time." },
  { id:10097, domain:1, level:2, question:"Which of the following BEST describes the role of the security steering committee in budget governance?", options:["A Approving all individual security purchases","B Managing day-to-day security expenditures","C Prioritizing security investments based on risk and strategic alignment","D Setting the total security budget"], correct:2, explanation:"The security steering committee provides governance oversight by prioritizing security investments based on risk management needs and strategic alignment, ensuring resources are allocated effectively." },
  { id:10098, domain:1, level:1, question:"Which of the following is the PRIMARY purpose of a security awareness program?", options:["A To ensure all employees understand their security responsibilities and act securely","B To teach employees how to perform penetration tests","C To satisfy regulatory compliance requirements","D To train technical staff on security operations"], correct:0, explanation:"Security awareness programs aim to ensure all employees understand their security responsibilities and develop the knowledge and behaviors needed to protect organizational information assets." },
  { id:10099, domain:1, level:3, question:"An organization is implementing a new governance framework. The BEST way to ensure long-term sustainability is to:", options:["A Hire a large security team to enforce the framework","B Embed security governance into existing business processes and decision-making","C Purchase advanced security technologies","D Focus primarily on achieving compliance certifications"], correct:1, explanation:"Embedding security governance into existing business processes and decision-making structures ensures sustainability by making security a natural part of how the organization operates rather than a separate function." },
  { id:10100, domain:1, level:2, question:"Which of the following describes the primary difference between a centralized and decentralized security governance model?", options:["A Centralized models have more security staff","B Decentralized models are always less effective","C In centralized models, security decisions are made by a central authority; in decentralized models, by business units","D Centralized models are only appropriate for large organizations"], correct:2, explanation:"In centralized governance, a central security function makes key decisions and sets standards; in decentralized models, business units have more autonomy, with tradeoffs in consistency versus flexibility." },
  { id:10101, domain:1, level:1, question:"The COBIT framework is owned and maintained by:", options:["A NIST","B ISO","C ISACA","D (ISC)²"], correct:2, explanation:"COBIT is owned and maintained by ISACA (Information Systems Audit and Control Association), which publishes updates and supporting guidance for the framework." },
  { id:10102, domain:1, level:2, question:"Which of the following BEST describes the purpose of a security governance review?", options:["A To test technical security controls for vulnerabilities","B To compare security technologies against industry peers","C To assess whether the governance framework is achieving its intended objectives","D To audit individual employee compliance with security policies"], correct:2, explanation:"Security governance reviews assess whether the governance framework, structures, and processes are functioning as intended and achieving security objectives aligned with business goals." },
  { id:10103, domain:1, level:3, question:"When developing security KPIs for board reporting, the MOST important consideration is:", options:["A Focusing on technical operational metrics","B Including as many metrics as possible for completeness","C Using industry-standard metrics regardless of organizational context","D Ensuring KPIs reflect business risk and support strategic decision-making"], correct:3, explanation:"Board-level KPIs must reflect the business risk implications of security and support strategic decision-making; metrics should be selected for relevance to the specific organization's objectives and risk profile." },
  { id:10104, domain:1, level:1, question:"Which of the following BEST describes the primary output of an effective information security governance framework?", options:["A Reduced technical vulnerabilities","B A fully staffed security operations center","C Compliance with all applicable regulations","D Consistent, risk-based management of information security aligned with business objectives"], correct:3, explanation:"An effective security governance framework produces consistent, risk-based security management that is aligned with business objectives, ensuring that security decisions support organizational goals." },
  { id:10105, domain:1, level:2, question:"In the context of security governance, 'due care' refers to:", options:["A Implementing the same controls as every other organization","B Taking reasonable steps to protect information assets based on identified risks","C Avoiding all possible security risks","D Complying only with mandatory regulations"], correct:1, explanation:"Due care means taking the reasonable steps and precautions that a prudent person would take to protect information assets, based on identified risks and the importance of those assets." },
  { id:10106, domain:1, level:2, question:"An information security governance framework should be evaluated against which of the following criteria FIRST?", options:["A Technical completeness of security controls","B Compliance with the most security regulations","C Adoption of the latest security technologies","D Alignment with business strategy and risk appetite"], correct:3, explanation:"The primary evaluation criterion for any security governance framework is whether it aligns with business strategy and risk appetite, as this determines whether the framework supports organizational objectives." },
  { id:10107, domain:1, level:3, question:"A healthcare organization is expanding services to additional jurisdictions. The CISO should FIRST:", options:["A Create separate security programs for each jurisdiction","B Implement the same security controls in all jurisdictions","C Map applicable regulatory requirements for each jurisdiction to the existing governance framework","D Wait for security incidents to identify regulatory gaps"], correct:2, explanation:"Mapping jurisdiction-specific regulatory requirements to the existing governance framework identifies gaps and required adaptations, enabling a risk-informed and efficient approach to multi-jurisdiction compliance." },
  { id:10108, domain:1, level:1, question:"Which of the following is MOST important when establishing security roles and responsibilities?", options:["A Ensuring all roles are filled by dedicated security professionals","B Assigning roles exclusively to the IT department","C Clearly defining accountability and authority for each role","D Having the maximum number of security roles possible"], correct:2, explanation:"Clearly defining accountability and authority for each security role is most important because without clear ownership and authority, security responsibilities will be overlooked or duplicated." },
  { id:10109, domain:1, level:2, question:"Which of the following activities BEST demonstrates that a security governance program is mature?", options:["A A large security budget has been approved","B Security policies are updated every three years","C The organization has not had a security breach in two years","D Security metrics are regularly reviewed and used to improve the program"], correct:3, explanation:"Using security metrics to drive continuous improvement demonstrates mature governance; it shows that the organization monitors, evaluates, and acts on security performance data systematically." },
  { id:10110, domain:1, level:2, question:"The PRIMARY purpose of establishing a security governance committee structure is to:", options:["A Manage day-to-day security incidents","B Reduce the workload on the CISO","C Replace the need for security policies","D Ensure cross-functional decision-making and accountability for security"], correct:3, explanation:"Committee structures provide cross-functional representation, enabling decisions that balance security with business needs and distributing accountability for security across the organization." },
  { id:10111, domain:1, level:3, question:"An organization has implemented many security controls but continues to experience significant breaches. The MOST likely root cause from a governance perspective is:", options:["A Lack of alignment between security controls and actual business risks","B Insufficient security technology investment","C The security team is not large enough","D Attackers are too sophisticated"], correct:0, explanation:"Persistent breaches despite control investment often indicate a governance failure — the controls implemented don't address the actual risks facing the organization, pointing to poor risk-to-control alignment." },
  { id:10112, domain:1, level:1, question:"Which of the following is the BEST example of a security governance outcome?", options:["A Patching all vulnerabilities within 30 days","B Installing a new SIEM platform","C Conducting monthly phishing simulations","D Defined accountability for information security across all business units"], correct:3, explanation:"Defining accountability for security across business units is a governance outcome because it establishes the organizational structures and responsibilities that enable security management." },
  { id:10113, domain:1, level:2, question:"Which concept describes the situation where multiple layers of governance or oversight exist for the same security activity?", options:["A Dual control","B Redundant governance","C Defense in depth","D Overlapping authorities"], correct:2, explanation:"Defense in depth is the security concept of using multiple layers of controls; in governance, overlapping responsibilities can serve a similar purpose, but 'defense in depth' is the recognized term for layered security." },
  { id:10114, domain:1, level:1, question:"An organization's information security policy should be approved by:", options:["A The CISO","B The IT department head","C Senior management or the board of directors","D The security steering committee"], correct:2, explanation:"Information security policies should be approved by senior management or the board to demonstrate top-level commitment and provide the authority needed for policy enforcement." },
  { id:10115, domain:1, level:3, question:"When selecting a security governance framework, an organization should PRIMARILY consider:", options:["A Frameworks that align with the organization's specific industry, size, and risk profile","B The most popular framework in the industry","C The framework that is least expensive to implement","D The framework with the most comprehensive technical controls"], correct:0, explanation:"Framework selection should be driven by fit to the organization's specific context, including industry requirements, organizational size, risk profile, and regulatory environment, not generic popularity." },
  { id:10116, domain:1, level:2, question:"Which of the following is the MOST effective way to communicate security governance expectations to employees?", options:["A Annual security training","B Sending quarterly security newsletters","C Posting security policies on the intranet","D Integrating security expectations into onboarding, performance management, and communications"], correct:3, explanation:"Integrating security expectations into ongoing business processes like onboarding and performance management is most effective because it embeds security into how the organization operates daily." },
  { id:10117, domain:1, level:2, question:"Which of the following BEST describes the relationship between information security governance and risk management?", options:["A They are entirely separate functions","B Governance provides the framework within which risk management operates","C Risk management directs governance activities","D They are the same function with different names"], correct:1, explanation:"Security governance establishes the structures, policies, and accountability that provide the framework within which risk management processes are conducted and decisions are made." },
  { id:10118, domain:1, level:1, question:"The CISO MOST directly reports to which of the following for maximum governance effectiveness?", options:["A The CIO","B The CFO","C The legal department","D The board of directors or CEO"], correct:3, explanation:"CISOs reporting to the CEO or board have greater authority, visibility, and independence, enabling more effective security governance without the potential conflicts of interest from reporting through IT." },
  { id:10119, domain:1, level:3, question:"An organization's security governance is described as 'defined.' Using a maturity model, what is the PRIMARY next step for improvement?", options:["A Implement measurement and metrics to manage and optimize security","B Create a security policy","C Document all security processes","D Hire more security staff"], correct:0, explanation:"Moving from 'defined' (level 3 in most maturity models) to 'managed' (level 4) requires implementing quantitative measurement and metrics to monitor and control security processes." },
  { id:10120, domain:1, level:2, question:"Which of the following BEST represents the governance principle of 'transparency'?", options:["A Providing stakeholders with accurate and timely information about security risks and performance","B Sharing all security incident details with employees","C Eliminating all classified security information","D Making all security information publicly available"], correct:0, explanation:"Transparency in governance means providing relevant stakeholders with accurate, timely information about security risks and program performance to support informed decision-making and accountability." },
  { id:10121, domain:1, level:1, question:"Which of the following is MOST important when developing a security governance framework for a new organization?", options:["A Starting with the most comprehensive framework available","B Copying the framework from a similar organization","C Understanding the organization's mission, objectives, and risk tolerance","D Implementing all security controls immediately"], correct:2, explanation:"Understanding the organization's mission, objectives, and risk tolerance is foundational to developing a governance framework that is fit for purpose and supports the organization's specific needs." },
  { id:10122, domain:1, level:2, question:"Which of the following BEST describes the concept of 'security governance maturity'?", options:["A The age of an organization's security program","B The number of security certifications an organization holds","C The size of the organization's security budget","D The progressive levels of capability in security governance from ad hoc to optimized"], correct:3, explanation:"Security governance maturity describes the progressive development of governance capabilities through levels such as initial/ad hoc, repeatable, defined, managed, and optimizing." },
  { id:10123, domain:1, level:3, question:"A board of directors is considering a merger with a company that has had recent security breaches. From a governance perspective, the CISO should:", options:["A Recommend against the merger","B Conduct a security due diligence assessment and present risk findings to the board","C Require the target company to fix all vulnerabilities before proceeding","D Inform the board that security is not a relevant merger consideration"], correct:1, explanation:"The CISO's governance role in M&A is to conduct thorough security due diligence and provide the board with the information needed to make an informed risk-based decision about the merger." },
  { id:10124, domain:1, level:1, question:"Which of the following BEST describes an information security governance framework?", options:["A A structured collection of policies, processes, roles, and metrics to govern information security","B A set of technical controls for protecting information","C A compliance checklist for regulatory requirements","D A vendor assessment program for security products"], correct:0, explanation:"An information security governance framework is a structured collection of policies, processes, roles, and metrics that provides the foundation for governing security decisions and activities." },
  { id:10125, domain:1, level:2, question:"Which of the following is a key responsibility of an organization's data owners?", options:["A Determining the classification and acceptable use of data","B Physically securing data storage hardware","C Performing backups of data","D Implementing technical access controls"], correct:0, explanation:"Data owners, typically business managers, are responsible for determining data classification and defining acceptable use policies for the data within their business domain." },
  { id:10126, domain:1, level:2, question:"A federated security governance model BEST describes:", options:["A All security decisions made by a central corporate security team","B A model where only outsourced vendors make security decisions","C Security governed entirely by individual business units","D A hybrid model where central policies are set but business units have implementation flexibility"], correct:3, explanation:"A federated governance model balances centralized policy-setting and oversight with decentralized implementation, allowing business units flexibility within a common framework." },
  { id:10127, domain:1, level:3, question:"After a major security breach, the board asks for governance improvements. The MOST effective long-term improvement is to:", options:["A Purchase more security tools","B Hire additional security staff","C Increase penalties for policy violations","D Integrate security risk into enterprise risk management and board-level reporting"], correct:3, explanation:"Integrating security risk into enterprise risk management and board-level reporting creates sustainable governance improvement by ensuring security receives ongoing executive attention and resources as a business risk." },
  { id:10128, domain:1, level:1, question:"Which of the following documents provides specific, mandatory technical requirements for implementing security controls?", options:["A Policy","B Guideline","C Procedure","D Standard"], correct:3, explanation:"Standards provide specific, mandatory technical requirements that detail how policies are to be implemented, such as minimum password length or encryption algorithm requirements." },
  { id:10129, domain:1, level:2, question:"Which of the following BEST describes the role of the board in security budget governance?", options:["A The board should not be involved in security budget decisions","B The board should approve all individual security purchases","C The board should determine which security tools are purchased","D The board should ensure adequate resources are allocated to manage security risk"], correct:3, explanation:"The board's governance role is to ensure that the organization allocates adequate resources to manage security risk appropriately, not to make individual purchasing decisions." },
  { id:10130, domain:1, level:3, question:"An organization is preparing to adopt a new security governance framework. Which of the following is the MOST important first step?", options:["A Select the framework before analyzing the organization","B Implement all framework requirements simultaneously","C Conduct a gap assessment comparing current state to the desired framework","D Hire a consulting firm to implement the framework"], correct:2, explanation:"A gap assessment comparing the current state to the desired framework identifies what changes are needed, enabling a prioritized, resource-efficient implementation roadmap." },
  { id:10131, domain:1, level:1, question:"Which type of governance document would contain step-by-step instructions for responding to a data breach?", options:["A Security policy","B Security standard","C Security procedure","D Security charter"], correct:2, explanation:"Procedures contain detailed, step-by-step instructions for performing specific tasks; a data breach response procedure would walk staff through each required action in the response process." },
  { id:10132, domain:1, level:2, question:"The MOST important reason for establishing a formal information security governance program is to:", options:["A Satisfy regulatory requirements","B Ensure security is managed strategically and consistently as an organizational risk","C Reduce the cost of security controls","D Demonstrate security capability to customers"], correct:1, explanation:"The most important reason for formal security governance is to ensure security is managed as a strategic organizational concern with consistent processes, accountability, and alignment to business risk." },
  { id:10133, domain:1, level:2, question:"Which of the following BEST describes the concept of 'strategic alignment' in security governance?", options:["A Using the same security framework as industry peers","B Ensuring security initiatives support and enable the organization's business strategy","C Aligning security resources with technical requirements","D Having all security staff report to the same executive"], correct:1, explanation:"Strategic alignment means ensuring that security initiatives, investments, and priorities support and enable the organization's business strategy, making security a business enabler rather than an obstacle." },
  { id:10134, domain:1, level:3, question:"A CISO is developing a security strategy for an organization that is shifting to a cloud-first model. The MOST important governance consideration is:", options:["A Whether existing security tools are cloud-compatible","B Whether the cloud provider is ISO 27001 certified","C How cloud adoption affects risk and how governance structures need to adapt","D The cost of cloud security solutions"], correct:2, explanation:"The governance consideration is how the cloud-first shift changes the organization's risk profile and what adaptations to governance structures, policies, and responsibilities are needed to manage that risk." },
  { id:10135, domain:1, level:1, question:"Which of the following is MOST likely to be a direct output of an information security strategy?", options:["A A list of security tools to purchase","B A multi-year roadmap for improving security capabilities aligned with business objectives","C A detailed incident response plan","D A configuration baseline for servers"], correct:1, explanation:"An information security strategy produces a multi-year roadmap that defines how security capabilities will be developed and improved in alignment with business objectives and risk management goals." },
  { id:10136, domain:1, level:2, question:"In the context of security governance, 'due diligence' refers to:", options:["A Continuously exercising reasonable care to understand and manage security risks","B Following up on all security incidents","C Implementing all possible security controls","D Completing all required security certifications"], correct:0, explanation:"Due diligence involves continuously exercising reasonable care to understand and manage security risks, going beyond minimum requirements to actively identify and address potential threats." },
  { id:10137, domain:1, level:2, question:"Which of the following BEST represents a governance control for managing third-party security risks?", options:["A Performing annual penetration tests of third-party systems","B Requiring all third parties to use the same security tools","C Establishing third-party security requirements in contracts and monitoring compliance","D Prohibiting the use of third parties for all sensitive operations"], correct:2, explanation:"Governance over third-party risk requires establishing contractual security requirements and ongoing monitoring of compliance, ensuring third parties meet the organization's security standards." },
  { id:10138, domain:1, level:3, question:"Which of the following BEST describes a key challenge in implementing security governance in a highly decentralized organization?", options:["A Balancing consistent standards with business unit autonomy and different risk profiles","B Having too many security staff","C Having too many security tools to manage","D Achieving ISO 27001 certification across all units"], correct:0, explanation:"In decentralized organizations, the key challenge is balancing the need for consistent baseline standards with the legitimate differences in risk profiles, operations, and autonomy of individual business units." },
  { id:10139, domain:1, level:1, question:"Which of the following activities is MOST associated with the 'Evaluate' function of security governance?", options:["A Training security staff","B Deploying new security controls","C Responding to security incidents","D Assessing whether current security practices are meeting organizational objectives"], correct:3, explanation:"The 'Evaluate' governance function involves assessing whether security practices, controls, and the overall program are meeting their intended objectives and providing needed protection." },
  { id:10140, domain:1, level:2, question:"Which of the following BEST demonstrates executive accountability for information security?", options:["A Executives owning identified security risks and being accountable for remediation","B The board reviewing security reports quarterly","C The CISO attending all board meetings","D Executives completing annual security awareness training"], correct:0, explanation:"True executive accountability means that executives own the security risks in their domain and are held answerable for remediation, not just receiving reports or completing training." },
  { id:10141, domain:1, level:2, question:"The MOST important factor in developing an effective security culture is:", options:["A Mandatory security training for all employees","B Visible and consistent security behavior from leadership","C Large investment in security awareness tools","D Strict enforcement of security policy violations"], correct:1, explanation:"Culture is shaped most powerfully by the behavior of leaders; when executives and managers consistently model security-conscious behavior, it signals that security is genuinely valued." },
  { id:10142, domain:1, level:3, question:"An organization's security team frequently bypasses established governance processes to respond to urgent situations. The BEST corrective action is to:", options:["A Review and update governance processes to accommodate legitimate operational needs","B Require all exceptions to be approved by the board","C Eliminate the governance processes that are being bypassed","D Discipline the security team"], correct:0, explanation:"If governance processes are consistently bypassed, they are likely not fit for purpose; reviewing and updating them to accommodate legitimate operational needs improves compliance and effectiveness." },
  { id:10143, domain:1, level:1, question:"The purpose of classifying information is PRIMARILY to:", options:["A Make data easier to store and retrieve","B Determine appropriate protection levels based on data sensitivity and value","C Satisfy regulatory requirements","D Facilitate data sharing across departments"], correct:1, explanation:"Information classification enables the organization to apply appropriate protection levels based on the sensitivity, value, and criticality of information assets." },
  { id:10144, domain:1, level:2, question:"Which of the following is the MOST important principle when defining security governance roles?", options:["A Roles should be held by the most senior employees","B Accountability should be clearly assigned and not duplicated","C As many staff as possible should have governance roles","D Security governance roles should be voluntary"], correct:1, explanation:"Clear, non-duplicated accountability assignment is the most important principle; when multiple parties share accountability without clear delineation, ownership gaps and conflicts arise." },
  { id:10145, domain:1, level:2, question:"Which of the following BEST describes why security governance requires regular review and update?", options:["A The threat landscape, business environment, and regulatory requirements continuously evolve","B To justify the security budget","C To satisfy auditors","D To demonstrate the security team is active"], correct:0, explanation:"Regular review and update of security governance is necessary because the threat landscape, business environment, technologies, and regulatory requirements are constantly changing." },
  { id:10146, domain:1, level:3, question:"A CISO is presenting a new security governance framework to skeptical senior management. The MOST effective approach is to:", options:["A Frame the framework in terms of business risk reduction and strategic enablement","B Present compliance requirements that mandate the framework","C Lead with technical security requirements","D Use fear-based messaging about potential breaches"], correct:0, explanation:"Presenting governance in terms of business risk reduction and strategic enablement speaks to management's priorities, making the business case for security investment more compelling than technical or fear-based arguments." },
  { id:10147, domain:1, level:1, question:"Which of the following BEST represents the governance principle of 'responsibility' in security?", options:["A All employees are responsible for everything","B Only the security team has security responsibilities","C Each individual understands and fulfills their specific security obligations","D Responsibility is shared equally across all departments"], correct:2, explanation:"The governance principle of responsibility means that each individual and organizational unit understands and fulfills their specific, defined security obligations within the overall governance structure." },
  { id:10148, domain:1, level:2, question:"Which of the following BEST describes the relationship between security governance and security management?", options:["A They are the same thing","B Governance sets direction and oversight; management implements and operates","C Management sets direction; governance implements","D They operate completely independently"], correct:1, explanation:"Security governance (board/executive level) establishes strategic direction and oversight, while security management implements that direction and operates day-to-day security processes." },
  { id:10149, domain:1, level:1, question:"An information security strategy should be reviewed and updated at minimum:", options:["A Every five years","B Annually or when significant changes occur","C Only after a major security incident","D Whenever new security technologies emerge"], correct:1, explanation:"Security strategies should be reviewed annually and whenever significant changes in the business, threat landscape, or regulatory environment occur to ensure continued relevance and effectiveness." },
  { id:10150, domain:1, level:3, question:"An organization's internal audit identifies that security governance processes exist but are not consistently followed. The MOST likely root cause is:", options:["A Lack of awareness, training, or enforcement mechanisms for the processes","B The processes are not needed","C The processes are too detailed","D Employees prefer different processes"], correct:0, explanation:"Processes that exist but are not consistently followed typically indicate insufficient awareness of requirements, inadequate training, or ineffective enforcement mechanisms within the governance program." },
  { id:10151, domain:1, level:2, question:"Which of the following BEST describes how ISO 27001 differs from NIST CSF?", options:["A ISO 27001 is voluntary; NIST CSF is mandatory","B ISO 27001 is a certifiable standard; NIST CSF is a voluntary framework","C ISO 27001 applies only to financial services; NIST CSF is cross-industry","D There is no significant difference between them"], correct:1, explanation:"ISO 27001 is an international standard against which organizations can be formally certified, while NIST CSF is a voluntary framework for improving cybersecurity risk management without formal certification." },
  { id:10152, domain:1, level:1, question:"Which of the following BEST describes the governance concept of 'tone at the top'?", options:["A Executive compensation tied to security performance","B The security standards set by the most senior technical staff","C The example and attitude set by senior leadership regarding security","D The top-priority security risks for the organization"], correct:2, explanation:"'Tone at the top' refers to the example, attitude, and commitment demonstrated by senior leaders regarding security; it is a key driver of organizational security culture." },
  { id:10153, domain:1, level:2, question:"Which of the following is the PRIMARY driver for including security in corporate governance?", options:["A Regulatory requirements","B Customer demands for security","C Technical complexity of modern IT systems","D Protection of organizational value and management of security as a business risk"], correct:3, explanation:"The primary driver is the recognition that security risk is a business risk that can destroy organizational value; integrating it into corporate governance ensures it receives appropriate strategic attention." },
  { id:10154, domain:1, level:3, question:"When developing a security governance framework for an organization operating in a highly regulated industry, the CISO should FIRST:", options:["A Implement all regulatory requirements immediately","B Map regulatory requirements to business objectives to identify overlaps and gaps","C Hire specialized compliance staff","D Adopt the most comprehensive available framework"], correct:1, explanation:"Mapping regulatory requirements to business objectives identifies where compliance supports business goals and where gaps exist, enabling a risk-based and efficient approach to governance design." },
  { id:10155, domain:1, level:1, question:"Which of the following BEST describes the purpose of a security policy exception process?", options:["A To allow security controls to be permanently disabled","B To provide a formal, risk-managed pathway for legitimate deviations from security requirements","C To exempt senior executives from security requirements","D To document security policy violations for disciplinary purposes"], correct:1, explanation:"An exception process provides a formal, governed pathway for managing legitimate situations where compliance with a security requirement is not possible or practical, ensuring exceptions are risk-managed." },
  { id:10156, domain:1, level:2, question:"Which of the following BEST demonstrates the integration of security governance and business continuity?", options:["A Testing the disaster recovery system annually","B Having separate security and business continuity plans","C Embedding security requirements into business continuity planning processes","D Assigning the CISO responsibility for business continuity"], correct:2, explanation:"Integrating security into business continuity planning ensures that security requirements are considered in continuity scenarios and that recovery processes maintain appropriate security controls." },
  { id:10157, domain:1, level:2, question:"Which of the following BEST describes how security governance supports regulatory compliance?", options:["A It replaces the need for regulatory compliance programs","B It delegates compliance responsibility to external auditors","C It ensures organizations exceed all regulatory requirements","D It provides the structures and processes for identifying, implementing, and monitoring compliance requirements"], correct:3, explanation:"Security governance provides the structures, processes, and accountability needed to identify applicable regulations, implement required controls, and monitor ongoing compliance effectively." },
  { id:10158, domain:1, level:3, question:"An organization's CISO has limited authority and resources despite documented governance responsibilities. The MOST effective corrective action is:", options:["A Documenting the authority gap more thoroughly","B Accepting the limitation and working within constraints","C Hiring additional staff to compensate for resource limitations","D Escalating to the board to formally realign CISO authority with responsibilities"], correct:3, explanation:"When documented authority does not match actual authority, board-level escalation and formal realignment is needed; governance gaps of this nature require executive action to correct." },
  { id:10159, domain:1, level:1, question:"Which of the following BEST represents an information security governance 'outcome'?", options:["A A firewall rule change","B A phishing simulation exercise","C Organizational accountability and behaviors that protect information assets","D A vulnerability scan report"], correct:2, explanation:"Governance outcomes are the actual behaviors, accountabilities, and organizational conditions created by governance activities, such as consistent security behaviors and clear accountability structures." },
  { id:10160, domain:1, level:2, question:"Which of the following BEST describes how security governance should address emerging threats?", options:["A Incorporating emerging threat monitoring into governance processes and updating strategy accordingly","B Waiting for regulations to address new threats before responding","C Implementing new controls immediately when threats emerge","D Deferring all emerging threat response to the technical security team"], correct:0, explanation:"Governance should institutionalize ongoing monitoring of the threat landscape and incorporate findings into regular strategy reviews and updates, ensuring the program adapts to emerging risks." },
  { id:10161, domain:1, level:1, question:"In the context of information security governance, 'value delivery' refers to:", options:["A Ensuring security investments provide business value through risk reduction","B Delivering security reports to management on time","C Providing security training to all employees","D Meeting all compliance deadlines"], correct:0, explanation:"Value delivery in governance means ensuring that security investments and activities provide actual business value through risk reduction, not just compliance or activity completion." },
  { id:10162, domain:1, level:3, question:"An organization discovers that different business units have developed conflicting security practices. The MOST appropriate governance response is to:", options:["A Allow each business unit to maintain its own practices","B Penalize business units for non-conformance","C Establish a governance process for harmonizing practices while respecting legitimate business differences","D Immediately standardize all security practices centrally"], correct:2, explanation:"Harmonizing practices through a governance process balances consistency with legitimate business needs, resolving conflicts while avoiding both rigid uniformity and unacceptable fragmentation." },
  { id:10163, domain:1, level:2, question:"Which of the following BEST describes the governance principle of 'resource optimization' in security?", options:["A Minimizing the security budget","B Ensuring security resources are allocated to address the highest risks effectively","C Maximizing the number of security staff","D Using only open-source security tools"], correct:1, explanation:"Resource optimization means allocating security investments — people, technology, and budget — to the areas of highest risk, maximizing security effectiveness per dollar spent." },
  { id:10164, domain:1, level:2, question:"Which of the following BEST illustrates that an organization has achieved 'optimized' security governance maturity?", options:["A Security is continuously improved using metrics and feedback across the organization","B The security team has completed all planned training","C All security policies have been documented","D The organization has been audited with no findings"], correct:0, explanation:"Optimized maturity is characterized by continuous improvement driven by metrics and feedback, with security embedded throughout the organization and processes being constantly refined." },
  { id:10165, domain:1, level:1, question:"Which of the following is the BEST reason for separating the CISO role from the CIO role?", options:["A To reduce the IT department's workload","B To ensure security oversight is independent of IT operations","C To allow the CISO to report directly to the CFO","D To create separate budgets for security and IT"], correct:1, explanation:"Separating CISO and CIO roles ensures that security oversight remains independent from IT operations, avoiding conflicts of interest and ensuring security receives dedicated executive focus." },
  { id:10166, domain:1, level:3, question:"An organization is deciding whether to build an internal security governance capability or outsource it. The MOST important governance consideration is:", options:["A Cost comparison of insourcing versus outsourcing","B Whether external providers have better security expertise","C Whether the organization can maintain accountability and control of security risk if outsourced","D The preference of the board of directors"], correct:2, explanation:"The critical governance consideration is whether the organization can maintain appropriate accountability and control over security risk in an outsourced model, as governance accountability cannot be fully delegated." },
  { id:10167, domain:1, level:1, question:"Which of the following BEST describes why executive sponsorship is critical for a security governance program?", options:["A Executives can override security controls when needed","B Sponsorship provides authority, visibility, and resources needed for governance effectiveness","C Only executives understand security requirements","D Sponsorship reduces the CISO's workload"], correct:1, explanation:"Executive sponsorship provides the authority, organizational visibility, and resource commitment needed for a security governance program to be effective and taken seriously across the organization." },
  { id:10168, domain:1, level:2, question:"Which of the following BEST describes the governance concept of 'performance measurement' in security?", options:["A Measuring the technical performance of security tools","B Evaluating individual employee security performance","C Establishing and monitoring metrics to assess whether security governance objectives are being achieved","D Counting the number of security controls deployed"], correct:2, explanation:"Performance measurement in governance involves establishing metrics aligned to governance objectives and regularly monitoring them to assess whether the security program is achieving its goals." },
  { id:10169, domain:1, level:2, question:"When should security governance policies be communicated to employees?", options:["A Only when an employee violates a policy","B Only during annual security training","C Upon hiring, whenever policies change, and regularly throughout employment","D When requested by the employee"], correct:2, explanation:"Policies should be communicated upon hiring to establish expectations, whenever they change to ensure currency, and regularly throughout employment to maintain awareness and compliance." },
  { id:10170, domain:1, level:3, question:"A large organization is implementing a security governance framework for the first time. To maximize adoption, the CISO should:", options:["A Focus only on technical controls initially","B Implement the full framework at once","C Hire external consultants to design and implement the framework without stakeholder involvement","D Engage business stakeholders early to understand needs and gain buy-in for the framework"], correct:3, explanation:"Early stakeholder engagement builds understanding of business needs and generates buy-in, which is essential for adoption and long-term sustainability of a new governance framework." },
  { id:10171, domain:1, level:1, question:"Which of the following BEST describes the purpose of security governance reporting to the board?", options:["A To demonstrate the security team's technical competence","B To report all security incidents in technical detail","C To provide the board with information needed to fulfill their oversight responsibilities","D To justify the security team's budget requests"], correct:2, explanation:"Board security reporting exists to give directors the information they need to fulfill their fiduciary oversight responsibilities and make informed decisions about security risk." },
  { id:10172, domain:1, level:2, question:"Which of the following MOST accurately describes the concept of 'information security risk tolerance'?", options:["A The number of unpatched vulnerabilities considered acceptable","B The maximum number of security incidents acceptable per year","C The percentage of the budget allocated to managing security risk","D The level of security risk an organization is willing to accept after controls are applied"], correct:3, explanation:"Risk tolerance is the acceptable level of residual risk remaining after controls are applied, reflecting what the organization is willing to accept in pursuit of its objectives." },
  { id:10173, domain:1, level:3, question:"An organization's security policy requires annual review, but business units frequently resist updates. The MOST effective governance approach is to:", options:["A Remove the annual review requirement","B Reduce the scope of policies to avoid business unit resistance","C Involve business unit representatives in the review process to increase ownership","D Enforce compliance through disciplinary action"], correct:2, explanation:"Involving business unit representatives in policy reviews increases their ownership and understanding, making them advocates for updates rather than sources of resistance." },
  { id:10174, domain:1, level:1, question:"Which of the following BEST describes the concept of 'accountability' versus 'responsibility' in security governance?", options:["A They are the same concept applied to different levels","B Responsibility applies to executives; accountability applies to staff","C Accountability can be shared; responsibility cannot","D Accountability is being answerable for outcomes; responsibility is performing specific tasks"], correct:3, explanation:"Accountability means being answerable for outcomes (typically non-delegable for senior leaders), while responsibility means being assigned to perform specific tasks (which can be delegated)." },
  { id:10175, domain:1, level:2, question:"Which of the following BEST describes how a security governance framework addresses human resource security?", options:["A By conducting background checks on all employees","B By implementing technical monitoring of all employee activities","C By requiring all employees to have security certifications","D By defining security responsibilities in employment agreements and throughout the employment lifecycle"], correct:3, explanation:"Human resource security governance means embedding security requirements throughout the employment lifecycle, from hiring through termination, including contractual obligations and ongoing expectations." },
  { id:10176, domain:1, level:2, question:"Which of the following is the BEST indicator that security governance is effectively integrated with business governance?", options:["A Security policies are reviewed by legal counsel","B Security has a dedicated budget line item","C The CISO attends all IT meetings","D Security risk appears on the enterprise risk register and in board discussions"], correct:3, explanation:"When security risk is integrated into the enterprise risk register and discussed at board level, it demonstrates true integration of security governance with overall business governance." },
  { id:10177, domain:1, level:3, question:"A CISO is asked to present the security governance maturity roadmap to the board. The roadmap should PRIMARILY focus on:", options:["A Technical security capabilities to be developed","B Compliance certifications to be achieved","C How governance improvements will reduce business risk over time","D The number of security tools to be implemented"], correct:2, explanation:"A board-level governance maturity roadmap should focus on how planned improvements will reduce business risk and better support organizational objectives, translating capability development into business terms." },
  { id:10178, domain:1, level:1, question:"Which of the following BEST describes a 'hybrid' security governance model?", options:["A A model that combines on-premises and cloud security tools","B A model that uses both insourced and outsourced security staff","C A model that blends centralized standards with decentralized execution","D A model that applies different standards to different data types"], correct:2, explanation:"A hybrid governance model sets centralized policies and standards while allowing individual business units flexibility in how they implement and operate those requirements." },
  { id:10179, domain:1, level:2, question:"Which of the following BEST describes the governance purpose of a security exception register?", options:["A To track security incidents","B To record security policy violations","C To monitor employee compliance with training requirements","D To document and manage risks associated with approved deviations from security policies"], correct:3, explanation:"An exception register documents approved deviations from security policies, the risks they present, compensating controls, and review timelines, enabling ongoing management of exception-related risk." },
  { id:10180, domain:1, level:3, question:"When designing security governance metrics, which of the following MOST clearly indicates a lagging indicator?", options:["A Percentage of employees completing security training","B Number of security incidents in the past quarter","C Percentage of assets with current risk assessments","D Number of security policies reviewed this year"], correct:1, explanation:"Lagging indicators measure outcomes after they have occurred; the number of past incidents is a lagging indicator, while training completion and risk assessment coverage are leading indicators of future performance." },
  { id:10181, domain:1, level:1, question:"Which of the following BEST describes the role of senior management in information security governance?", options:["A Performing day-to-day security operations","B Setting the strategic direction and ensuring security aligns with business objectives","C Implementing technical security controls","D Conducting security awareness training"], correct:1, explanation:"Senior management's governance role is to set strategic direction for security, allocate resources, and ensure the security program aligns with and supports business objectives." },
  { id:10182, domain:1, level:2, question:"Which of the following BEST describes why security standards need to be updated more frequently than security policies?", options:["A Standards are less important than policies","B Standards reflect specific technologies and practices that change faster than high-level principles","C Policies are not subject to change","D Standards are reviewed by more people than policies"], correct:1, explanation:"Standards address specific technologies, configurations, and practices that evolve rapidly, while policies state enduring principles; this difference in stability drives different review frequencies." },
  { id:10183, domain:1, level:2, question:"Which of the following BEST represents the governance concept of 'strategic planning' in information security?", options:["A Planning the annual security budget","B Scheduling security training for all staff","C Defining multi-year security objectives aligned with business strategy and risk management goals","D Planning the technical architecture of security systems"], correct:2, explanation:"Strategic planning in security governance defines multi-year objectives, capabilities, and initiatives that align security investment with business strategy and long-term risk management goals." },
  { id:10184, domain:1, level:3, question:"An organization's security governance committee has become dominated by IT department representatives. The BEST corrective action is to:", options:["A Eliminate the committee and have the CISO make all decisions","B Ensure diverse business representation to provide appropriate cross-functional oversight","C Replace all IT representatives with business unit representatives","D Require all committee decisions to be approved by the board"], correct:1, explanation:"Security governance committees need diverse business representation to ensure that security decisions reflect cross-functional perspectives and are aligned with business needs across the organization." },
  { id:10185, domain:1, level:1, question:"Which of the following MOST accurately describes information security governance in a highly regulated industry?", options:["A Governance only needs to meet minimum regulatory requirements","B Governance must integrate regulatory compliance while also addressing broader business security risks","C Regulations fully define the security governance framework","D External auditors are responsible for security governance"], correct:1, explanation:"In regulated industries, governance must satisfy regulatory requirements while also addressing the full range of business security risks, as regulations typically represent minimum floors rather than comprehensive programs." },
  { id:10186, domain:1, level:2, question:"Which of the following BEST describes the role of risk assessments in security governance?", options:["A They provide input for governance decisions about security priorities and resource allocation","B They define the technical security architecture","C They are conducted solely to satisfy auditors","D They replace the need for security policies"], correct:0, explanation:"Risk assessments provide the data and analysis needed to inform governance decisions about which risks to prioritize, how to allocate resources, and what level of residual risk to accept." },
  { id:10187, domain:1, level:3, question:"An organization wants to establish a security governance program that is sustainable long-term. The MOST important design principle is:", options:["A Making the program as comprehensive as possible from day one","B Designing the program to be scalable, adaptable, and embedded in business processes","C Ensuring the program can operate without dedicated security staff","D Building the program around the current CISO's preferences"], correct:1, explanation:"Sustainable governance programs are designed to be scalable, adaptable to change, and embedded in business processes so they function effectively regardless of personnel changes or business evolution." },
  { id:10188, domain:1, level:1, question:"The MOST important characteristic of security policies is that they:", options:["A Are as detailed as possible","B Are written by security experts","C Are reviewed by legal counsel","D Have senior management endorsement and clear expectations"], correct:3, explanation:"The most important characteristic of security policies is that they carry senior management endorsement and communicate clear expectations, providing the authority and direction needed for enforcement." },
  { id:10189, domain:1, level:2, question:"Which of the following BEST describes why security governance cannot be a one-time activity?", options:["A Security technology changes constantly","B Security staff turn over frequently","C The business environment, threats, regulations, and organizational context all continuously evolve","D Auditors require annual reviews"], correct:2, explanation:"Security governance must be ongoing because all the factors that shape security requirements — the business, threats, technologies, and regulations — continuously evolve, requiring adaptation." },
  { id:10190, domain:1, level:2, question:"Which of the following BEST describes the concept of 'business impact analysis' in the context of security governance?", options:["A Assessing the financial impact of purchasing new security tools","B Analyzing the impact of security policies on business operations","C Measuring the cost of implementing security controls","D Evaluating the potential business consequences of security failures to prioritize governance activities"], correct:3, explanation:"Business impact analysis evaluates the potential business consequences of security failures, providing governance decision-makers with the information needed to prioritize protections appropriately." },
  { id:10191, domain:1, level:3, question:"A CISO is developing an annual report on the state of security governance for the board. The report should PRIMARILY address:", options:["A Technical details of security controls implemented","B Security program performance against objectives, key risks, and recommended adjustments","C A list of security incidents and their technical causes","D Budget expenditures for the security team"], correct:1, explanation:"Board security reports should summarize program performance against stated objectives, highlight key risks requiring attention, and recommend strategic adjustments — not operational or technical details." },
  { id:10192, domain:1, level:1, question:"Which of the following BEST represents a key output of the 'Direct' function in security governance?", options:["A Security incident response actions","B Vulnerability scan results","C Security objectives, policies, and resource allocations","D Security awareness training content"], correct:2, explanation:"The 'Direct' governance function produces the strategic guidance that shapes the security program, including security objectives, approved policies, and resource allocation decisions." },
  { id:10193, domain:1, level:2, question:"Which of the following BEST describes a 'governance risk indicator' in security?", options:["A A metric that measures technical vulnerability counts","B A benchmark comparison to industry security spending","C A regulatory compliance checklist item","D An indicator that signals potential failures or weaknesses in governance processes"], correct:3, explanation:"Governance risk indicators signal potential weaknesses or failures in governance processes themselves, enabling proactive identification and remediation of governance gaps before they result in security failures." },
  { id:10194, domain:1, level:2, question:"Which of the following BEST describes how the security governance framework should address cloud computing?", options:["A Prohibit the use of cloud services","B Extend governance policies and controls to cover cloud services and define shared responsibility","C Delegate all security governance to the cloud service provider","D Treat cloud services the same as on-premises without modification"], correct:1, explanation:"Cloud governance requires extending existing policies to cover cloud use and clearly defining the shared responsibility model between the organization and cloud providers for security controls." },
  { id:10195, domain:1, level:3, question:"An organization's board has decided to accept a significant security risk without compensating controls. The CISO should:", options:["A Immediately notify regulators","B Implement controls anyway without informing the board","C Resign in protest","D Document the risk acceptance formally and ensure the board's decision is recorded"], correct:3, explanation:"When the board formally accepts a risk, the CISO's governance responsibility is to ensure the decision is properly documented, including the rationale and any conditions, to create an auditable record of the informed decision." },
  { id:10196, domain:1, level:1, question:"Which of the following BEST describes the purpose of a security governance 'charter'?", options:["A To describe the technical security architecture","B To provide step-by-step security procedures","C To establish the authority, scope, and mandate for the information security function","D To document all security incidents"], correct:2, explanation:"A security governance charter formally establishes the authority, scope, mission, and mandate of the information security function, providing the organizational foundation for the security program." },
  { id:10197, domain:1, level:2, question:"Which of the following is the MOST important element of a security governance reporting structure?", options:["A Reports should be as long as possible to be comprehensive","B Reports should use technical terminology to demonstrate expertise","C Reports should only focus on positive outcomes","D Reports should be tailored to the decision-making needs of each audience"], correct:3, explanation:"Effective security governance reporting must be tailored to the decision-making needs of each audience — board-level, executive, operational — so that recipients receive actionable, relevant information." },
  { id:10198, domain:1, level:3, question:"An organization has implemented security governance based on COBIT. Which of the following BEST indicates that the EDM domain is functioning effectively?", options:["A Security controls are documented and tested","B The board regularly evaluates security objectives and monitors program performance","C Security incidents are responded to quickly","D Security audits are conducted annually"], correct:1, explanation:"COBIT's EDM (Evaluate, Direct, Monitor) domain functions effectively when the board actively evaluates security objectives, provides strategic direction, and monitors program performance against stated goals." },
  { id:10199, domain:1, level:2, question:"Which of the following BEST describes the governance concept of 'continuous improvement' in information security?", options:["A Implementing new security tools every year","B Increasing the security budget each year","C Using performance data, lessons learned, and emerging threats to regularly enhance the security program","D Conducting annual penetration tests"], correct:2, explanation:"Continuous improvement in security governance means systematically using performance data, incident lessons learned, and threat intelligence to regularly enhance governance processes and security capabilities." },
  { id:10200, domain:1, level:2, question:"Which of the following BEST describes the governance concept of 'segregation of duties' in a small organization with limited staff?", options:["A Segregation of duties is not applicable in small organizations","B Compensating controls should be implemented where full segregation is not possible","C All duties should be assigned to a single trusted individual","D Segregation of duties only applies to financial processes"], correct:1, explanation:"When full segregation of duties is not feasible due to staffing limitations, compensating controls such as enhanced logging, supervisory review, and periodic audits should be implemented to reduce risk." },
  { id:10201, domain:1, level:1, question:"Which of the following BEST describes the purpose of a security awareness training program within governance?", options:["A To replace security controls with human vigilance","B To ensure employees understand and fulfill their security responsibilities","C To satisfy annual compliance training requirements only","D To train employees to perform security audits"], correct:1, explanation:"Security awareness programs within governance ensure that all employees understand their security responsibilities and have the knowledge needed to fulfill them effectively." },
  { id:10202, domain:1, level:3, question:"An organization's security governance program lacks board-level engagement. The MOST effective strategy to improve this is:", options:["A Send detailed technical reports to all board members","B Translate security risks into business and financial impact language relevant to board concerns","C Require all board members to attend security training","D Escalate security incidents directly to the chairman"], correct:1, explanation:"Board engagement improves when security risks are presented in business and financial terms that resonate with directors' responsibilities, rather than in technical language they may not connect to their oversight duties." },
  { id:10203, domain:1, level:2, question:"Which of the following BEST represents a 'leading indicator' in security governance metrics?", options:["A Number of data breaches in the past year","B Percentage of systems with current security patches applied","C Total financial losses from security incidents","D Number of regulatory fines received"], correct:1, explanation:"Leading indicators measure factors that predict future outcomes; patch coverage percentage predicts vulnerability exposure and is a forward-looking metric, unlike incident counts or financial losses which are lagging." },
  { id:10204, domain:1, level:1, question:"Which governance principle requires that individuals cannot deny having performed an action?", options:["A Confidentiality","B Integrity","C Accountability","D Non-repudiation"], correct:3, explanation:"Non-repudiation ensures that an individual cannot deny having performed an action, typically supported through audit trails, digital signatures, and authentication mechanisms." },
  { id:10205, domain:1, level:2, question:"An organization's security governance framework should PRIMARILY be designed to:", options:["A Prevent all security incidents","B Comply with the maximum number of security frameworks","C Achieve the highest possible security maturity level","D Enable informed risk-based security decisions aligned with business objectives"], correct:3, explanation:"A governance framework should be designed to enable consistent, informed, risk-based security decisions that align with and support business objectives, not to achieve perfection or maximum control." },
  { id:10206, domain:1, level:3, question:"A security governance review reveals that security investments are not reducing risk as expected. The MOST likely governance failure is:", options:["A Insufficient security budget","B Security staff are not technically skilled enough","C The organization is using the wrong security framework","D Lack of connection between risk assessment results and security investment decisions"], correct:3, explanation:"When investments don't reduce risk, the root cause is typically a governance failure — security resources are being allocated based on factors other than actual risk, pointing to a broken risk-to-investment linkage." },
  { id:10207, domain:1, level:1, question:"Which of the following BEST describes why a security policy must be enforceable?", options:["A To give the security team legal authority","B Policies only have value if violations carry criminal penalties","C To satisfy external auditors","D Unenforced policies create false confidence and are treated as optional"], correct:3, explanation:"An unenforced policy creates a false sense of security and signals that compliance is optional, undermining the entire policy framework and organizational security culture." },
  { id:10208, domain:1, level:2, question:"Which of the following governance activities BEST ensures that security spending is efficient?", options:["A Purchasing only well-known security products","B Minimizing the security budget each year","C Aligning security investments with the risk register and tracking return on security investment","D Having all security purchases approved by the CEO"], correct:2, explanation:"Aligning investments with the risk register and tracking return on security investment ensures resources address actual risks and that spending is producing measurable security value." },
  { id:10209, domain:1, level:2, question:"Which of the following BEST describes the purpose of a security program charter from a governance perspective?", options:["A To formally establish the mandate, authority, and scope of the security program","B To document security incidents and their resolutions","C To list all security tools the organization uses","D To provide technical guidance on security architecture"], correct:0, explanation:"A security program charter formally establishes the organizational mandate, authority boundaries, and scope of the security function, providing the governance foundation for all security activities." },
  { id:10210, domain:1, level:3, question:"An organization is considering outsourcing its security governance function to a managed service provider. The PRIMARY governance risk is:", options:["A The organization cannot fully outsource accountability for security risk","B The managed service provider may not use the latest security tools","C Managed service providers charge too much","D The organization will lose technical security expertise"], correct:0, explanation:"While security management activities can be outsourced, ultimate accountability for security risk to stakeholders cannot be delegated; the organization remains accountable for the security posture regardless of outsourcing." },
  { id:10211, domain:1, level:1, question:"Which of the following BEST describes the concept of 'information security governance integration'?", options:["A Integrating the security team with the IT operations team","B Integrating all security technologies into a single platform","C Embedding security governance into enterprise governance, risk, and compliance processes","D Connecting all security monitoring tools to a single dashboard"], correct:2, explanation:"Integration of security governance means embedding it into the broader enterprise governance, risk, and compliance (GRC) ecosystem so that security risk is managed as part of overall organizational governance." },
  { id:10212, domain:1, level:2, question:"The MOST important benefit of a well-defined information security governance structure is:", options:["A Consistent and accountable security decision-making aligned with business objectives","B Eliminating the need for security technologies","C Reducing the size of the security team needed","D Guaranteeing the prevention of security incidents"], correct:0, explanation:"A well-defined governance structure produces consistent, accountable security decision-making that aligns with business objectives — the foundation that makes all other security activities effective." },
  { id:10213, domain:1, level:3, question:"An organization is implementing security governance for the first time after years of operating without a formal program. The BEST approach to prioritization is:", options:["A Prioritize governance activities based on risk and potential business impact","B Start with the least disruptive governance changes","C Focus first on achieving compliance certifications","D Implement all governance requirements simultaneously"], correct:0, explanation:"When establishing governance for the first time, risk-based prioritization ensures that the most impactful governance activities are implemented first, providing the greatest risk reduction with available resources." },
  { id:10214, domain:1, level:1, question:"Which of the following BEST describes the difference between 'risk appetite' and 'risk tolerance'?", options:["A They are identical concepts","B Risk appetite applies to the board; risk tolerance applies to management","C Risk appetite is the desired state; risk tolerance is the acceptable deviation from that state","D Risk tolerance is for strategic risks; risk appetite is for operational risks"], correct:2, explanation:"Risk appetite is the overall desired level of risk the organization will accept in pursuit of objectives, while risk tolerance is the acceptable deviation from that appetite for specific situations." },
  { id:10215, domain:1, level:2, question:"Which of the following governance activities BEST supports the principle of 'continuous monitoring'?", options:["A Conducting annual security assessments","B Establishing automated, ongoing monitoring of security metrics and controls","C Reviewing security policies every two years","D Scheduling quarterly security audits"], correct:1, explanation:"Continuous monitoring requires automated, ongoing collection and analysis of security metrics and control performance, providing real-time visibility into the security posture rather than periodic snapshots." },
  { id:10216, domain:1, level:2, question:"Which of the following BEST demonstrates that security governance is outcomes-focused rather than activity-focused?", options:["A Measuring the number of security controls implemented","B Measuring the reduction in business risk achieved by security activities","C Tracking the number of security staff training hours","D Counting the number of security policies in place"], correct:1, explanation:"Outcomes-focused governance measures what security activities achieve — actual risk reduction — rather than counting activities, inputs, or the presence of controls." },
  { id:10217, domain:1, level:3, question:"A CISO discovers that the security governance framework was designed for a different threat environment than currently exists. The MOST appropriate action is to:", options:["A Replace the entire framework immediately","B Conduct a targeted review and update the framework components that no longer address current threats","C Continue using the existing framework to maintain consistency","D Implement ad hoc controls outside the framework"], correct:1, explanation:"A targeted, evidence-based review and update of components that are no longer current is more effective and efficient than wholesale replacement, preserving what remains relevant while addressing gaps." },
  { id:10218, domain:1, level:1, question:"Which of the following BEST describes the primary purpose of a security policy hierarchy?", options:["A To document all security controls in use","B To give the security team multiple documents to reference","C To ensure compliance with multiple regulatory frameworks","D To create a layered structure where general direction flows to specific requirements and instructions"], correct:3, explanation:"A policy hierarchy provides a layered structure where high-level policy direction is refined into standards, then procedures, ensuring consistent and specific guidance that flows from organizational intent." },
  { id:10219, domain:1, level:2, question:"Which of the following BEST describes how a CISO should address conflicts between security governance requirements and agile development practices?", options:["A Require all development to follow traditional waterfall methodologies","B Integrate security governance requirements into agile processes through DevSecOps practices","C Exempt agile development from security governance requirements","D Conduct security reviews only after all development is complete"], correct:1, explanation:"DevSecOps integrates security governance requirements into agile development practices, enabling rapid delivery while maintaining security oversight and control throughout the development lifecycle." },
  { id:10220, domain:1, level:3, question:"Which of the following BEST explains why security governance effectiveness cannot be measured solely by the absence of security incidents?", options:["A Incidents are too rare to be a useful measure","B Absence of incidents may reflect luck rather than effective governance","C Technical controls, not governance, prevent incidents","D The cost of preventing incidents is not tracked"], correct:1, explanation:"The absence of incidents can reflect many factors including luck, undetected incidents, or attacker disinterest; effective governance must be measured by process maturity, risk reduction, and alignment to objectives." },
  { id:10221, domain:1, level:1, question:"Which of the following BEST describes why information security governance requires cross-functional participation?", options:["A Security tools are used by all departments","B Cross-functional teams are more productive","C IT cannot make all security decisions alone","D Security risks and responsibilities span all business functions, not just IT"], correct:3, explanation:"Security risks and responsibilities exist across all business functions; effective governance requires participation from the business units who own the risks and are responsible for managing them." },
  { id:10222, domain:1, level:2, question:"Which of the following MOST accurately describes the governance role of internal audit in information security?", options:["A Internal audit reports to the CISO","B Internal audit implements security controls","C Internal audit provides independent assurance that security governance is operating as intended","D Internal audit is responsible for security policy development"], correct:2, explanation:"Internal audit provides independent assurance to the board and management that security governance processes and controls are operating effectively and as designed, supporting oversight." },
  { id:10223, domain:1, level:2, question:"An organization's security governance framework should treat privacy governance as:", options:["A Less important than security governance","B A completely separate program from security governance","C A compliance matter handled solely by legal","D An integrated element, since privacy and security controls significantly overlap"], correct:3, explanation:"Privacy and security governance are closely related, with overlapping controls and objectives; treating them as integrated programs avoids duplication, reduces gaps, and improves overall effectiveness." },
  { id:10224, domain:1, level:3, question:"A security steering committee is considering whether to invest in advanced threat intelligence. The governance decision should PRIMARILY be based on:", options:["A Whether the investment addresses risks that materially threaten the organization's objectives","B The technical capabilities of the security team","C Whether competitors are using threat intelligence","D The cost of the intelligence service"], correct:0, explanation:"Governance investment decisions should be driven by whether the investment addresses material risks to organizational objectives, ensuring resources are allocated based on business risk rather than technology trends or peer practices." },
  { id:10225, domain:1, level:1, question:"Which of the following BEST represents the governance concept of 'assurance' in information security?", options:["A Guaranteeing that no security incidents will occur","B Ensuring all security policies are documented","C Certifying that all staff have completed security training","D Providing confidence that security controls and governance are effective"], correct:3, explanation:"Assurance in security governance means providing stakeholders with confidence — through evidence and evaluation — that security controls and governance processes are effective and achieving their objectives." },
  { id:10226, domain:1, level:2, question:"Which of the following BEST describes how security governance should handle legacy systems that cannot meet current security standards?", options:["A Immediately decommission all legacy systems","B Apply the same standards regardless of technical feasibility","C Exempt legacy systems from all security requirements","D Accept the risk formally or apply compensating controls, documented through the exception process"], correct:3, explanation:"Legacy systems that cannot meet current standards should go through the formal exception process, with compensating controls implemented where possible and residual risk formally accepted and documented." },
  { id:10227, domain:1, level:3, question:"An organization's security governance program generates many reports but rarely leads to action. The MOST likely governance failure is:", options:["A There are too many security reports","B Reports are too detailed","C Reporting is not connected to decision-making processes or accountability structures","D Reports are not written by the CISO"], correct:2, explanation:"When reports don't drive action, the governance failure is typically that reporting is disconnected from decision-making processes and accountability structures — generating information without connecting it to authority or responsibility to act." },
  { id:10228, domain:1, level:1, question:"Which of the following BEST describes the responsibility of a process owner in security governance?", options:["A Ensuring the security of the information processed and the compliance of the process with security requirements","B Auditing the security of the process annually","C Writing the security policies applicable to the process","D Technically implementing the security controls for a process"], correct:0, explanation:"Process owners are responsible for ensuring that their processes operate securely, including that information processed is adequately protected and that security requirements are incorporated into process design and operation." },
  { id:10229, domain:1, level:2, question:"Which of the following MOST accurately describes the governance principle of 'defense in depth' from a governance perspective?", options:["A Implementing multiple layers of the same type of security control","B Using security tools from multiple different vendors","C Ensuring governance structures include multiple oversight layers and compensating controls","D Having multiple security teams with overlapping responsibilities"], correct:2, explanation:"From a governance perspective, defense in depth means creating multiple layers of oversight and accountability, ensuring that no single point of governance failure can lead to undetected security breakdown." },
  { id:10230, domain:1, level:3, question:"A CISO is building the case for investing in security governance improvements. The MOST compelling argument for the CFO is:", options:["A The organization has not had a security incident recently","B Mature security governance reduces the cost of security operations and regulatory compliance over time","C Security governance is required by regulations","D The competitor has invested in security governance"], correct:1, explanation:"The most compelling financial argument is that mature governance reduces the total cost of security over time by improving efficiency, reducing incidents, and streamlining compliance activities — framing governance as a cost-saving investment." },
  { id:10231, domain:1, level:1, question:"Which of the following BEST describes the 'Monitor' function in a security governance framework?", options:["A Tracking security program performance and ensuring objectives are being achieved","B Monitoring network traffic for security threats","C Conducting employee monitoring for policy compliance","D Deploying security monitoring tools"], correct:0, explanation:"The 'Monitor' governance function involves tracking security program performance against established objectives and metrics, ensuring the program is achieving its goals and enabling corrective action." },
  { id:10232, domain:1, level:2, question:"Which of the following BEST describes the relationship between security governance and incident response?", options:["A Security governance replaces the need for incident response","B Security governance provides the authority structure and decision rights needed to respond effectively to incidents","C Incident response is purely an operational function with no governance component","D Security governance and incident response operate independently"], correct:1, explanation:"Security governance establishes the authority structures, decision rights, and escalation paths that enable effective incident response, including determining when incidents require executive or board notification." },
  { id:10233, domain:1, level:3, question:"An organization is preparing for a security governance audit. The MOST important evidence of governance effectiveness is:", options:["A A complete set of written security policies","B Security certification badges from multiple frameworks","C Documentation showing that governance processes are executed consistently and drive security decisions","D A large security team organizational chart"], correct:2, explanation:"Governance effectiveness is evidenced not just by the existence of policies but by proof that governance processes are consistently executed and actually influence security decisions and outcomes." },
  { id:10234, domain:1, level:1, question:"Which of the following BEST describes an appropriate security governance reporting frequency for the board?", options:["A Daily security incident reports","B Quarterly or semi-annual strategic security risk briefings","C Real-time security dashboard access","D Annual compliance audit reports only"], correct:1, explanation:"Board-level governance typically requires quarterly or semi-annual strategic briefings on security risk and program performance, providing sufficient frequency for oversight without overwhelming directors with operational detail." },
  { id:10235, domain:1, level:2, question:"Which of the following MOST directly demonstrates that security governance is aligned with business strategy?", options:["A Security initiatives in the roadmap directly support identified business strategic objectives","B The security team uses business-friendly terminology","C The security budget matches industry benchmarks","D The CISO participates in business strategy meetings"], correct:0, explanation:"True strategic alignment is demonstrated when security initiatives in the roadmap can be directly traced to and shown to support specific business strategic objectives." },
  { id:10236, domain:1, level:2, question:"Which of the following BEST describes the governance concept of 'risk-based decision-making' in information security?", options:["A Making security decisions based on regulatory requirements alone","B Making security decisions based on the lowest possible cost option","C Avoiding all risks regardless of cost","D Prioritizing security activities and investments based on assessed risk levels"], correct:3, explanation:"Risk-based decision-making in governance means using risk assessment results to prioritize and justify security activities and investments, ensuring resources address the highest risks first." },
  { id:10237, domain:1, level:3, question:"An organization's security governance program has been in place for five years without major updates. The MOST significant risk is:", options:["A The program may no longer address current threats, business changes, or regulatory requirements","B The security team has become too comfortable","C The security technology is outdated","D The security budget needs to be increased"], correct:0, explanation:"A governance program that has not been updated over five years risks being misaligned with the current threat landscape, evolved business operations, and updated regulatory requirements." },
  { id:10238, domain:1, level:1, question:"Which of the following MOST accurately describes the 'scope' of an information security governance program?", options:["A Only systems that handle customer data","B Only the IT department and its systems","C The full range of people, processes, technology, and information assets the program governs","D External-facing systems and networks only"], correct:2, explanation:"The scope of a security governance program should encompass all people, processes, technologies, and information assets that the program is responsible for governing, regardless of location or ownership." },
  { id:10239, domain:1, level:2, question:"Which of the following BEST describes how security governance should address the use of personal devices for work (BYOD)?", options:["A Prohibit all personal device use","B Require all employees to use company-issued devices only","C Allow unrestricted personal device use","D Establish governance policies that define acceptable use, security requirements, and monitoring for personal devices"], correct:3, explanation:"BYOD governance requires defining clear policies covering acceptable use, minimum security requirements, and monitoring expectations, balancing employee flexibility with organizational security needs." },
  { id:10240, domain:1, level:3, question:"A CISO is asked to assess whether the current security governance framework adequately addresses emerging AI risks. The MOST appropriate first step is to:", options:["A Review the existing governance framework against AI risk scenarios and identify gaps","B Create a completely separate AI governance program","C Purchase AI-specific security tools","D Wait for regulatory guidance on AI security"], correct:0, explanation:"Assessing the existing framework against new AI risk scenarios identifies specific gaps that can be addressed through targeted updates, enabling efficient and coherent governance adaptation rather than building a redundant program." }
];
